import math

class Solution(object):
    def minimumK(self, nums):
        # nonPositive(nums, k) = sum of ceil(nums[i] / k) for all i
        # We want the minimum k such that sum(ceil(nums[i]/k)) <= k^2
        # Binary search on k in [1, max(nums)]

        def ops(k):
            return sum(math.ceil(v / k) for v in nums)

        lo, hi = 1, max(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if ops(mid) <= mid * mid:
                hi = mid
            else:
                lo = mid + 1
        return lo
